import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import org.mockito.stubbing.Answer;

import java.lang.reflect.Constructor;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void format_singleValue_success() throws IOException {
        String result = csvFormat.format("value");
        assertEquals("value", result);
    }

    @Test
    void format_multipleValues_success() throws IOException {
        String result = csvFormat.format("val1", "val2", "val3");
        assertEquals("val1,val2,val3", result);
    }

    @Test
    void format_nullValue_success() throws IOException {
        CSVFormat format = csvFormat.withNullString("NULL");
        String result = format.format((Object) null);
        assertEquals("NULL", result);
    }

    @Test
    void format_emptyValues_success() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void format_ioException_throwsIllegalStateException() throws Exception {
        // Use reflection to override CSVPrinter constructor to return a mock that throws IOException on printRecord
        Constructor<CSVPrinter> constructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        constructor.setAccessible(true);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord(any());
        doNothing().when(mockPrinter).close();

        // Use a proxy CSVFormat subclass to override print method to return our mockPrinter
        CSVFormat spyFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                null,
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter()) {
            @Override
            public CSVPrinter print(final Appendable out) throws IOException {
                return mockPrinter;
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            spyFormat.format("value1");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
